  ('aboriginal-0a2fc18c-moex-00276', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-110-6ed013db', 'sub-aboriginal-0a2fc18c-07', NULL, 'single_choice', '有關民主原則，下列敘述何者錯誤？', '["我國憲政體制係採直接民主制", "我國之主權屬於全體國民", "人民行使國家主權的方式，多係透過投票的方式為之", "原則上以多數決定之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:42+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "405", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00277', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-110-6ed013db', 'sub-aboriginal-0a2fc18c-07', NULL, 'single_choice', '憲法及增修條文關於「軍人」之規定，下列敘述何者錯誤？', '["現役軍人不得兼任文官", "現役軍人應受軍事審判", "國家應對軍人退役後之就學、就業予以保障", "全國陸海空軍應超出黨派"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:42+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "405", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00278', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-110-6ed013db', 'sub-aboriginal-0a2fc18c-07', NULL, 'single_choice', '依司法院釋字第756號解釋意旨，關於憲法秘密通訊自由，下列敘述何者錯誤？', '["受刑人在監禁期間，人身自由遭受限制，惟其秘密通訊自由等基本權利，仍受憲法之保障", "監獄長官閱讀受刑人發受書信，涉及對秘密通訊自由核心內涵之干預", "監獄長官為確認有無夾帶違禁品而檢查受刑人書信，並不當然影響通訊內容之秘密性", "監獄長官令受刑人刪除書信部分內容後再發出，如以法律或法律具體明確授權之命令定之，即為憲 法所許"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:42+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "405", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00279', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-110-6ed013db', 'sub-aboriginal-0a2fc18c-07', NULL, 'single_choice', '依司法院大法官解釋，若法律規定國家對宗教之監督僅適用於佛、道教，未對其他宗教為相同之限制， 該法律規定是否合憲？', '["違憲，因為宗教自由乃是不得以法律限制之基本權", "違憲，因為宗教自由之限制乃是內政部之行政保留事項", "違憲，因為違反宗教中立原則與宗教平等原則", "合憲，因為國家對宗教自由得以法律為必要之限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:42+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "405", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00280', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-110-6ed013db', 'sub-aboriginal-0a2fc18c-07', NULL, 'single_choice', '關於憲法平等權，下列何者尚非司法院大法官解釋曾闡述之內涵？', '["對相同事物為差別待遇而無正當理由", "所採取分類與規範目的之達成間是否具一定關聯性", "是否以促進社會多元化為規範目的", "對於不同事物未為合理之差別待遇"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:42+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "405", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
  ('aboriginal-0a2fc18c-moex-00281', 'aboriginal-0a2fc18c', 'aboriginal-0a2fc18c-moex-110-6ed013db', 'sub-aboriginal-0a2fc18c-07', NULL, 'single_choice', '下列何者不屬於訴訟權之保障範圍？', '["裁判應妥速進行，不得耗時過久", "訴訟費用不得過高，超出人民可得負擔之程度", "所有訴訟程序，均應採取三級三審制", "人民提起之行政訴訟，應得請求暫時權利保護"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:42+00:00", "source_pdf_sha1": "6069e65a1298", "answer_pdf_sha1": "c5158b77d9cd", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "405", "s": "0213", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "經建行政"}'::jsonb, NULL),
